                                                                                                                                                                                             <div class="col-md-6 col-12 col-xl-3">
                                                                                                                                                                                                <div class="p-3">
                                                                                                                                                                                                   <div class="card card-news">
                                                                                                                                                                                                      <a href="/despacho/Documents/grupo-de-divulgacion-y-prensa/publicaciones-micasa/MiCASa%20-%20A%20Rajatabla%20(libro%20digital)_.pdf" title="A rajatabla" target="_blank"><img src="/despacho/PublishingImages/publicaciones-micasa/Portada%20A%20Rajatabla.jpg" alt="A rajatabla" style="width: 250px; height: 375px; box-shadow: rgba(0, 0, 0, 0.5) 2px 2px 4px;"/>​</a>
                                                                                                                                                                                                      <div class="card-body">
                                                                                                                                                                                                         <h4 class="card-temas" style="-webkit-line-clamp: 7;">A rajatabla. Síntesis comentada de los Hallazgos y Recomendaciones del Informe de la Comisión de la Verdad<br/></h4>
                                                                                                                                                                                                         <p class="txt-card-temas">Autor: Gustavo Gallón Giraldo<br/></p>
                                                                                                                                                                                                         <p class="txt-card-temas">Año: 2024<br/></p>
                                                                                                                                                                                                         <a href="/despacho/Documents/grupo-de-divulgacion-y-prensa/publicaciones-micasa/MiCASa%20-%20A%20Rajatabla%20(libro%20digital)_.pdf" class="btn-main" title="A rajatabla" target="_blank">DESCARGAR Y LEER</a><br/><br/>
